  ('pukao-6e11b43e-moex-00001', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '下列何者不是公部門管理與私部門管理之差異？', '["公部門管理具有獨占特質，而企業管理強調競爭", "公部門管理較可能會有金魚缸效應（goldfish-bowleffect）", "公部門的決策權力較為集中，而企業的決策程序較為分散與繁複", "企業的組織目標較明確，績效較容易衡量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "c09432b9175f", "answer_pdf_sha1": "dc420f888dc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00002', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '行政學有關政治與行政關係之敘述，下列何者正確？', '["威爾遜（W.Wilson）認為行政是政府行動的廣泛計畫，而政治是廣泛計畫的詳細執行", "行政學在美國總統羅斯福推行新政時期，脫離政治學成為一門獨立的學科", "行政學真正成為一門獨立學科，主要在於新公共管理的提倡之後", "學者古德諾（F.Goodnow）提倡政治與行政二分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "c09432b9175f", "answer_pdf_sha1": "dc420f888dc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00003', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '賽蒙（H.Simon）所著《行政行為》一書的觀點，使其獲得諾貝爾經濟學獎。下列何者不是此書的主張？', '["行政執行本身就是一種決策活動", "組織中從基層到高層，每一個人的決策理性程度決定了行政效率", "決策時可以完全理性地做出最佳的決策", "決策活動包括情報、設計以及抉擇，其中花在抉擇活動的時間最少"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "c09432b9175f", "answer_pdf_sha1": "dc420f888dc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00004', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '下列各公共行政學派內涵之敘述，何者錯誤？', '["新公共行政強調行政學者應價值中立", "新公共管理強調政府應以績效及結果為導向", "新公共管理主張政府應領航而不操槳", "新公共服務主張政府應服務而非領航"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "c09432b9175f", "answer_pdf_sha1": "dc420f888dc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00005', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '根據貝隆（C.Bellone）和葛爾（G.Goerl）的看法，新公共管理所鼓勵的企業家型官僚與民主政治之間可 能存在進退兩難的衝突或緊張關係，下列敘述何者錯誤？', '["企業自主與民主課責之間的衝突", "企業秘密與民主公開之間的衝突", "企業家個人遠見與公民參與之間的衝突", "企業永續發展與政權定期輪替之間的衝突"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "c09432b9175f", "answer_pdf_sha1": "dc420f888dc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00006', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '在彼得斯（B.G.Peters）所提出的治理模式中，主要來自於新左派的主張，並強調自發性管理，其所指的 是下列何者？', '["PFI模式", "參與模式", "公開模式", "非營利模式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "c09432b9175f", "answer_pdf_sha1": "dc420f888dc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00007', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '有關行政學修正理論（1930-1960年代）時期的論述，下列何者錯誤？', '["強調對於組織的動態面之研究", "需要層級理論屬於此一時期的學說", "著重於組織與外在環境之間的互動關係", "過分偏重於組織內成員行為之研究"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "c09432b9175f", "answer_pdf_sha1": "dc420f888dc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00008', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '由全球化的觀點分析，公共行政改革主要受到多重因素影響，下列何者不包含在其中？', '["全球化經濟的競爭", "資訊科技的衝擊", "資源不虞匱乏", "民主化的浪潮"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "c09432b9175f", "answer_pdf_sha1": "dc420f888dc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL)
